// // This ROM module outputs a 4-bit value based on a 4-bit input address. When the address is 0, it outputs 0; for address 1, it outputs 1; for address 2, it outputs 2; and for any other address, it outputs 3.
module top_module(
    addr,
    dout
);input [3:0] addr;
output [3:0] dout;
reg [3:0] dout;




always @(addr) begin: ROMPARMLOAD_READACTION
    case (addr)
        0: dout = 3;
        1: dout = 2;
        2: dout = 1;
        default: dout = 0;
    endcase
end

endmodule
